    [Fact]
    public void WFiltro_VistoHasValidValue_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var VistoValue = 1;
        var filtro = new FilterTribunal
        {
            Visto = VistoValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroTribunal(filtro);
