        VistoParameter.Value.Should().Be(VistoValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBTribunalDicInfo.PTabelaNome}].[{DBTribunalDicInfo.Visto}] = @{DBTribunalDicInfo.Visto}");
    }

